### 7. SHARED UTILITY FUNCTIONS FOR FORMATTING

**Text & Time Utilities:** `/home/haotiant/Projects/Personal/InstantNews/frontend/src/terminal-app.js` (lines 91-151)

```javascript
function formatTime(dateStr) {  // Lines 94-113
  if (!dateStr) return "--:--:--";
  try {
    const d = new Date(dateStr);
    return d.toLocaleTimeString("en-US", {
      hour: "2-digit", minute: "2-digit", second: "2-digit", hour12: false
    });
  } catch {
    return "";
  }
}

function timeAgo(dateStr) {  // Lines 116-140
  if (!dateStr) return "";
  try {
    const d = new Date(dateStr);
    const now = new Date();
    const diff = now - d;
    const minutes = Math.floor(diff / 60000);
    if (minutes < 1) return "now";
    if (minutes < 60) return `${minutes}m ago`;
    const hours = Math.floor(minutes / 60);
    if (hours < 24) return `${hours}h ago`;
    const days = Math.floor(hours / 24);
    return `${days}d ago`;
  } catch {
    return "";
  }
}

function escapeHtml(str) {  // Lines 142-146
  const div = document.createElement("div");
  div.textContent = str;
  return div.innerHTML;
}

function truncate(str, max) {  // Lines 148-151
  if (!str) return "";
  return str.length > max ? str.slice(0, max) + "…" : str;
}
```

