### 8. DATA FETCHING PATTERN

**Market Price Fetching:** `/home/haotiant/Projects/Personal/InstantNews/frontend/src/terminal-app.js` (lines 231-255)

```javascript
async function fetchMarketPrices() {
  if (!state.userFeatures.ai_ticker_recommendations) return;
  if (!state.columnVisibility.ticker) return;

  const tickers = [...new Set(state.items.filter(i => i.target_asset).map(i => i.target_asset))];
  const MAX_CONCURRENT_FETCHES = 5;

  for (let i = 0; i < tickers.length; i += MAX_CONCURRENT_FETCHES) {
    const batch = tickers.slice(i, i + MAX_CONCURRENT_FETCHES);
    const promises = batch.map(async (symbol) => {
      try {
        const res = await SignalAuth.fetch(`${API}/market/${encodeURIComponent(symbol)}`);
        if (res.ok) {
          state.marketPrices[symbol] = await res.json();
        }
      } catch (err) {
        logger.warn("Error fetching market price for", symbol, err);
      }
    });
    await Promise.all(promises);
  }
}
```

**Pattern for Company Details:** You should follow the same async/await pattern with `SignalAuth.fetch()` when fetching `/api/market/:symbol/details`

